import{_ as a,o as s,c as i,a2 as e}from"./chunks/framework.CGYl2SZ_.js";const l=JSON.parse('{"title":"04 whatsapp","description":"04 whatsapp 页面","frontmatter":{"title":"04 whatsapp","description":"04 whatsapp 页面"},"headers":[],"relativePath":"tutorials/04-whatsapp.md","filePath":"tutorials/04-whatsapp.md"}');const n=a({name:"tutorials/04-whatsapp.md"},[["render",function(a,l,n,t,h,p){return s(),i("div",null,[...l[0]||(l[0]=[e('<h1 id="whatsapp-渠道配置" tabindex="-1">WhatsApp 渠道配置 <a class="header-anchor" href="#whatsapp-渠道配置" aria-label="Permalink to &quot;WhatsApp 渠道配置&quot;">​</a></h1><blockquote><h2 id="文档索引" tabindex="-1">文档索引 <a class="header-anchor" href="#文档索引" aria-label="Permalink to &quot;文档索引&quot;">​</a></h2><p>获取完整文档索引：<a href="https://docs.openclaw.ai/llms.txt" target="_blank" rel="noreferrer">https://docs.openclaw.ai/llms.txt</a></p></blockquote><hr><h2 id="快速设置" tabindex="-1">快速设置 <a class="header-anchor" href="#快速设置" aria-label="Permalink to &quot;快速设置&quot;">​</a></h2><h3 id="步骤-1-配置-whatsapp-访问策略" tabindex="-1">步骤 1：配置 WhatsApp 访问策略 <a class="header-anchor" href="#步骤-1-配置-whatsapp-访问策略" aria-label="Permalink to &quot;步骤 1：配置 WhatsApp 访问策略&quot;">​</a></h3><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dmPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pairing&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      allowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;+15551234567&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groupPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowlist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      groupAllowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;+15551234567&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="步骤-2-链接-whatsapp-二维码" tabindex="-1">步骤 2：链接 WhatsApp（二维码） <a class="header-anchor" href="#步骤-2-链接-whatsapp-二维码" aria-label="Permalink to &quot;步骤 2：链接 WhatsApp（二维码）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whatsapp</span></span></code></pre></div><p>指定账户：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whatsapp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span></code></pre></div><h3 id="步骤-3-启动网关" tabindex="-1">步骤 3：启动网关 <a class="header-anchor" href="#步骤-3-启动网关" aria-label="Permalink to &quot;步骤 3：启动网关&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre></div><h3 id="步骤-4-批准第一个配对请求-如果使用配对模式" tabindex="-1">步骤 4：批准第一个配对请求（如果使用配对模式） <a class="header-anchor" href="#步骤-4-批准第一个配对请求-如果使用配对模式" aria-label="Permalink to &quot;步骤 4：批准第一个配对请求（如果使用配对模式）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whatsapp</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whatsapp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">COD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">E</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>配对请求 1 小时后过期。每个渠道待处理请求上限 3 个。</p><blockquote><p>💡 OpenClaw 推荐在可能情况下使用<strong>独立号码</strong>运行 WhatsApp（渠道元数据和引导流程为此优化，但个人号码设置也支持）</p></blockquote><hr><h2 id="部署模式" tabindex="-1">部署模式 <a class="header-anchor" href="#部署模式" aria-label="Permalink to &quot;部署模式&quot;">​</a></h2><h3 id="模式-1-专用号码-推荐" tabindex="-1">模式 1：专用号码（推荐） <a class="header-anchor" href="#模式-1-专用号码-推荐" aria-label="Permalink to &quot;模式 1：专用号码（推荐）&quot;">​</a></h3><p>最清晰的操作模式：</p><ul><li>独立的 WhatsApp 身份用于 OpenClaw</li><li>更清晰的 DM 白名单和路由边界</li><li>更低自聊天混淆风险</li></ul><p>最小策略模式：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      dmPolicy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;allowlist&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      allowFrom</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;+15551234567&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="模式-2-个人号码备用" tabindex="-1">模式 2：个人号码备用 <a class="header-anchor" href="#模式-2-个人号码备用" aria-label="Permalink to &quot;模式 2：个人号码备用&quot;">​</a></h3><p>引导支持个人号码模式并写入自聊天友好的基线配置：</p><ul><li><code>dmPolicy: &quot;allowlist&quot;</code></li><li><code>allowFrom</code> 包含你的个人号码</li><li><code>selfChatMode: true</code></li></ul><p>在运行时，自聊天保护基于链接的自号码和 <code>allowFrom</code>。</p><h3 id="模式-3-whatsapp-web-渠道范围" tabindex="-1">模式 3：WhatsApp Web 渠道范围 <a class="header-anchor" href="#模式-3-whatsapp-web-渠道范围" aria-label="Permalink to &quot;模式 3：WhatsApp Web 渠道范围&quot;">​</a></h3><p>消息平台渠道是基于 WhatsApp Web（<code>Baileys</code>）的。当前内置聊天渠道注册表中没有单独的 Twilio WhatsApp 消息渠道。</p><hr><h2 id="运行时模型" tabindex="-1">运行时模型 <a class="header-anchor" href="#运行时模型" aria-label="Permalink to &quot;运行时模型&quot;">​</a></h2><ul><li>Gateway 拥有 WhatsApp socket 和重连循环</li><li>出站发送需要目标账户的活动 WhatsApp 监听器</li><li>状态和广播聊天被忽略（<code>@status</code>、<code>@broadcast</code>）</li><li>直接聊天使用 DM 会话规则（<code>session.dmScope</code>；默认 <code>main</code> 将 DM 折叠到 agent main 会话）</li><li>群组会话隔离（<code>agent:&lt;agentId&gt;:whatsapp:group:&lt;jid&gt;</code>）</li></ul><hr><h2 id="访问控制和激活" tabindex="-1">访问控制和激活 <a class="header-anchor" href="#访问控制和激活" aria-label="Permalink to &quot;访问控制和激活&quot;">​</a></h2><h3 id="dm-策略" tabindex="-1">DM 策略 <a class="header-anchor" href="#dm-策略" aria-label="Permalink to &quot;DM 策略&quot;">​</a></h3><p><code>channels.whatsapp.dmPolicy</code> 控制直接聊天访问：</p><ul><li><code>pairing</code>（默认）</li><li><code>allowlist</code></li><li><code>open</code>（需要 <code>allowFrom</code> 包含 <code>&quot;*&quot;</code>）</li><li><code>disabled</code></li></ul><p><code>allowFrom</code> 接受 E.164 格式号码（内部标准化）。</p><p>多账户覆盖：<code>channels.whatsapp.accounts.&lt;id&gt;.dmPolicy</code>（和 <code>allowFrom</code>）优先于该账户的渠道级默认值。</p><p><strong>运行时行为</strong>：</p><ul><li>配对持久化在渠道允许存储中并与配置的 <code>allowFrom</code> 合并</li><li>如果没有配置白名单，链接的自号码默认允许</li><li>出站 <code>fromMe</code> DM 从不自配对</li></ul><h3 id="群组策略-白名单" tabindex="-1">群组策略 + 白名单 <a class="header-anchor" href="#群组策略-白名单" aria-label="Permalink to &quot;群组策略 + 白名单&quot;">​</a></h3><p>群组访问有两层：</p><ol><li><p><strong>群组成员白名单</strong>（<code>channels.whatsapp.groups</code>）</p><ul><li>如果省略 <code>groups</code>，所有群组合格</li><li>如果存在 <code>groups</code>，它作为群组白名单（允许 <code>&quot;*&quot;</code>）</li></ul></li><li><p><strong>群组发送者策略</strong>（<code>channels.whatsapp.groupPolicy</code> + <code>groupAllowFrom</code>）</p><ul><li><code>open</code>：发送者白名单绕过</li><li><code>allowlist</code>：发送者必须匹配 <code>groupAllowFrom</code>（或 <code>*</code>）</li><li><code>disabled</code>：阻止所有群组入站</li></ul></li></ol><p>发送者白名单回退：</p><ul><li>如果 <code>groupAllowFrom</code> 未设置，运行时在可用时回退到 <code>allowFrom</code></li><li>发送者白名单在提及/回复激活前评估</li></ul><p>注意：如果根本不存在 <code>channels.whatsapp</code> 块，运行时群组策略回退是 <code>allowlist</code>（带警告日志），即使设置了 <code>channels.defaults.groupPolicy</code>。</p><h3 id="提及-activation" tabindex="-1">提及 + /activation <a class="header-anchor" href="#提及-activation" aria-label="Permalink to &quot;提及 + /activation&quot;">​</a></h3><p>群组回复默认需要提及。</p><p>提及检测包括：</p><ul><li>明确的机器人身份 WhatsApp 提及</li><li>配置的提及正则模式（<code>agents.list[].groupChat.mentionPatterns</code>，回退 <code>messages.groupChat.mentionPatterns</code>）</li><li>隐式回复机器人检测（回复发送者匹配机器人身份）</li></ul><p><strong>安全说明</strong>：</p><ul><li>引用/回复仅满足提及门控，<strong>不</strong>授予发送者授权</li><li>使用 <code>groupPolicy: &quot;allowlist&quot;</code>，非白名单发送者仍被阻止，即使他们回复白名单用户的消息</li></ul><p>会话级激活命令：</p><ul><li><code>/activation mention</code></li><li><code>/activation always</code></li></ul><p><code>activation</code> 更新会话状态（不是全局配置）。它是所有者门控的。</p><hr><h2 id="个人号码和自聊天行为" tabindex="-1">个人号码和自聊天行为 <a class="header-anchor" href="#个人号码和自聊天行为" aria-label="Permalink to &quot;个人号码和自聊天行为&quot;">​</a></h2><p>当链接的自号码也存在于 <code>allowFrom</code> 中时，WhatsApp 自聊天 safeguard 激活：</p><ul><li>跳过自聊天回合的已读回执</li><li>忽略否则会自动 ping 你自己的提及-JID 自动触发行为</li><li>如果 <code>messages.responsePrefix</code> 未设置，自聊天回复默认 <code>[{identity.name}]</code> 或 <code>[openclaw]</code></li></ul><hr><h2 id="消息标准化和上下文" tabindex="-1">消息标准化和上下文 <a class="header-anchor" href="#消息标准化和上下文" aria-label="Permalink to &quot;消息标准化和上下文&quot;">​</a></h2><h3 id="入站信封-回复上下文" tabindex="-1">入站信封 + 回复上下文 <a class="header-anchor" href="#入站信封-回复上下文" aria-label="Permalink to &quot;入站信封 + 回复上下文&quot;">​</a></h3><p>入站 WhatsApp 消息包装在共享入站信封中。</p><p>如果存在引用回复，上下文以此形式附加：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Replying to &lt;sender&gt; id:&lt;stanzaId&gt;]</span></span>\n<span class="line"><span>&lt;quoted body or media placeholder&gt;</span></span>\n<span class="line"><span>[/Replying]</span></span></code></pre></div><p>回复元数据字段在可用时也填充（<code>ReplyToId</code>、<code>ReplyToBody</code>、<code>ReplyToSender</code>、发送者 JID/E.164）。</p><h3 id="媒体占位符和位置-联系人提取" tabindex="-1">媒体占位符和位置/联系人提取 <a class="header-anchor" href="#媒体占位符和位置-联系人提取" aria-label="Permalink to &quot;媒体占位符和位置/联系人提取&quot;">​</a></h3><p>仅媒体入站消息用占位符标准化：</p><ul><li><code>&lt;media:image&gt;</code></li><li><code>&lt;media:video&gt;</code></li><li><code>&lt;media:audio&gt;</code></li><li><code>&lt;media:document&gt;</code></li><li><code>&lt;media:sticker&gt;</code></li></ul><p>位置和联系人负载在路由前标准化为文本上下文。</p><h3 id="待处理群组历史注入" tabindex="-1">待处理群组历史注入 <a class="header-anchor" href="#待处理群组历史注入" aria-label="Permalink to &quot;待处理群组历史注入&quot;">​</a></h3><p>对于群组，未处理的消息可以缓冲并在机器人最终触发时注入为上下文。</p><ul><li>默认限制：<code>50</code></li><li>配置：<code>channels.whatsapp.historyLimit</code></li><li>回退：<code>messages.groupChat.historyLimit</code></li><li><code>0</code> 禁用</li></ul><p>注入标记：</p><ul><li><code>[Chat messages since your last reply - for context]</code></li><li><code>[Current message - respond to this]</code></li></ul><h3 id="已读回执" tabindex="-1">已读回执 <a class="header-anchor" href="#已读回执" aria-label="Permalink to &quot;已读回执&quot;">​</a></h3><p>已读回执默认对接受的入站 WhatsApp 消息启用。</p><p><strong>全局禁用</strong>：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      sendReadReceipts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>每个账户覆盖</strong>：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      accounts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        work</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          sendReadReceipts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>自聊天回合即使全局启用也跳过已读回执。</p><hr><h2 id="交付、分块和媒体" tabindex="-1">交付、分块和媒体 <a class="header-anchor" href="#交付、分块和媒体" aria-label="Permalink to &quot;交付、分块和媒体&quot;">​</a></h2><h3 id="文本分块" tabindex="-1">文本分块 <a class="header-anchor" href="#文本分块" aria-label="Permalink to &quot;文本分块&quot;">​</a></h3><ul><li>默认分块限制：<code>channels.whatsapp.textChunkLimit = 4000</code></li><li><code>channels.whatsapp.chunkMode = &quot;length&quot; | &quot;newline&quot;</code></li><li><code>newline</code> 模式偏好段落边界（空行），然后回退到长度安全分块</li></ul><h3 id="出站媒体行为" tabindex="-1">出站媒体行为 <a class="header-anchor" href="#出站媒体行为" aria-label="Permalink to &quot;出站媒体行为&quot;">​</a></h3><ul><li>支持图片、视频、音频（PTT 语音笔记）和文档负载</li><li><code>audio/ogg</code> 重写为 <code>audio/ogg; codecs=opus</code> 以兼容语音笔记</li><li>动画 GIF 播放通过 <code>gifPlayback: true</code> 在视频发送上支持</li><li>标题应用于发送多媒体回复负载时的第一个媒体项</li><li>媒体源可以是 HTTP(S)、<code>file://</code> 或本地路径</li></ul><h3 id="媒体大小限制和回退行为" tabindex="-1">媒体大小限制和回退行为 <a class="header-anchor" href="#媒体大小限制和回退行为" aria-label="Permalink to &quot;媒体大小限制和回退行为&quot;">​</a></h3><ul><li>入站媒体保存上限：<code>channels.whatsapp.mediaMaxMb</code>（默认 <code>50</code>）</li><li>出站媒体发送上限：<code>channels.whatsapp.mediaMaxMb</code>（默认 <code>50</code>）</li><li>每个账户覆盖使用 <code>channels.whatsapp.accounts.&lt;accountId&gt;.mediaMaxMb</code></li><li>图片自动优化（调整大小/质量扫描）以适应限制</li><li>媒体发送失败时，第一项回退发送文本警告而不是静默删除响应</li></ul><hr><h2 id="确认反应" tabindex="-1">确认反应 <a class="header-anchor" href="#确认反应" aria-label="Permalink to &quot;确认反应&quot;">​</a></h2><p>WhatsApp 支持通过 <code>channels.whatsapp.ackReaction</code> 在入站接收时立即确认反应。</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  channels</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    whatsapp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      ackReaction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        emoji</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;👀&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        direct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        group</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mentions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// always | mentions | never</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>行为说明</strong>：</p><ul><li>入站接受后立即发送（回复前）</li><li>失败记录但不阻止正常回复交付</li><li>群组模式 <code>mentions</code> 在提及触发的回合上反应；群组激活 <code>always</code> 作为绕过检查</li><li>WhatsApp 使用 <code>channels.whatsapp.ackReaction</code>（不使用传统的 <code>messages.ackReaction</code>）</li></ul><hr><h2 id="多账户和凭证" tabindex="-1">多账户和凭证 <a class="header-anchor" href="#多账户和凭证" aria-label="Permalink to &quot;多账户和凭证&quot;">​</a></h2><h3 id="账户选择和默认值" tabindex="-1">账户选择和默认值 <a class="header-anchor" href="#账户选择和默认值" aria-label="Permalink to &quot;账户选择和默认值&quot;">​</a></h3><ul><li>账户 ID 来自 <code>channels.whatsapp.accounts</code></li><li>默认账户选择：如果存在 <code>default</code>，否则第一个配置的账户 ID（排序）</li><li>账户 ID 在查找时内部标准化</li></ul><h3 id="凭证路径和传统兼容" tabindex="-1">凭证路径和传统兼容 <a class="header-anchor" href="#凭证路径和传统兼容" aria-label="Permalink to &quot;凭证路径和传统兼容&quot;">​</a></h3><ul><li>当前认证路径：<code>~/.openclaw/credentials/whatsapp/&lt;accountId&gt;/creds.json</code></li><li>备份文件：<code>creds.json.bak</code></li><li><code>~/.openclaw/credentials/</code> 中的传统默认认证仍被识别/迁移用于默认账户流程</li></ul><h3 id="登出行为" tabindex="-1">登出行为 <a class="header-anchor" href="#登出行为" aria-label="Permalink to &quot;登出行为&quot;">​</a></h3><p><code>openclaw channels logout --channel whatsapp [--account &lt;id&gt;]</code> 清除该账户的 WhatsApp 认证状态。</p><p>在传统认证目录中，<code>oauth.json</code> 保留而 Baileys 认证文件被删除。</p><hr><h2 id="工具、动作和配置写入" tabindex="-1">工具、动作和配置写入 <a class="header-anchor" href="#工具、动作和配置写入" aria-label="Permalink to &quot;工具、动作和配置写入&quot;">​</a></h2><ul><li>Agent 工具支持包括 WhatsApp 反应动作（<code>react</code>）</li><li>动作门控： <ul><li><code>channels.whatsapp.actions.reactions</code></li><li><code>channels.whatsapp.actions.polls</code></li></ul></li><li>渠道发起的配置写入默认启用（通过 <code>channels.whatsapp.configWrites=false</code> 禁用）</li></ul><hr><h2 id="故障排除" tabindex="-1">故障排除 <a class="header-anchor" href="#故障排除" aria-label="Permalink to &quot;故障排除&quot;">​</a></h2><h3 id="未链接-需要二维码" tabindex="-1">未链接（需要二维码） <a class="header-anchor" href="#未链接-需要二维码" aria-label="Permalink to &quot;未链接（需要二维码）&quot;">​</a></h3><p><strong>症状</strong>：渠道状态报告未链接</p><p><strong>修复</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --channel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whatsapp</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> channels</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><h3 id="已链接但断开连接-重连循环" tabindex="-1">已链接但断开连接/重连循环 <a class="header-anchor" href="#已链接但断开连接-重连循环" aria-label="Permalink to &quot;已链接但断开连接/重连循环&quot;">​</a></h3><p><strong>症状</strong>：链接账户重复断开或重连尝试</p><p><strong>修复</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --follow</span></span></code></pre></div><p>如需要，用 <code>channels login</code> 重新链接。</p><h3 id="发送时没有活动监听器" tabindex="-1">发送时没有活动监听器 <a class="header-anchor" href="#发送时没有活动监听器" aria-label="Permalink to &quot;发送时没有活动监听器&quot;">​</a></h3><p>出站发送在目标账户没有活动网关监听器时快速失败。</p><p>确保网关运行且账户已链接。</p><h3 id="群组消息意外被忽略" tabindex="-1">群组消息意外被忽略 <a class="header-anchor" href="#群组消息意外被忽略" aria-label="Permalink to &quot;群组消息意外被忽略&quot;">​</a></h3><p>按此顺序检查：</p><ul><li><code>groupPolicy</code></li><li><code>groupAllowFrom</code> / <code>allowFrom</code></li><li><code>groups</code> 白名单条目</li><li>提及门控（<code>requireMention</code> + 提及模式）</li><li><code>openclaw.json</code> 中的重复键（JSON5）：后面的条目覆盖前面的条目，所以每个范围保持单个 <code>groupPolicy</code></li></ul><h3 id="bun-运行时警告" tabindex="-1">Bun 运行时警告 <a class="header-anchor" href="#bun-运行时警告" aria-label="Permalink to &quot;Bun 运行时警告&quot;">​</a></h3><p>WhatsApp 网关运行时应该使用 Node。Bun 被标记为不兼容稳定的 WhatsApp/Telegram 网关操作。</p><hr><h2 id="配置参考指针" tabindex="-1">配置参考指针 <a class="header-anchor" href="#配置参考指针" aria-label="Permalink to &quot;配置参考指针&quot;">​</a></h2><p><strong>主要参考</strong>：<a href="/gateway/configuration-reference.html#whatsapp">配置参考 - WhatsApp</a></p><p><strong>高信号 WhatsApp 字段</strong>：</p><ul><li>访问：<code>dmPolicy</code>、<code>allowFrom</code>、<code>groupPolicy</code>、<code>groupAllowFrom</code>、<code>groups</code></li><li>交付：<code>textChunkLimit</code>、<code>chunkMode</code>、<code>mediaMaxMb</code>、<code>sendReadReceipts</code>、<code>ackReaction</code></li><li>多账户：<code>accounts.&lt;id&gt;.enabled</code>、<code>accounts.&lt;id&gt;.authDir</code>、账户级覆盖</li><li>操作：<code>configWrites</code>、<code>debounceMs</code>、<code>web.enabled</code>、<code>web.heartbeatSeconds</code>、<code>web.reconnect.*</code></li><li>会话行为：<code>session.dmScope</code>、<code>historyLimit</code>、<code>dmHistoryLimit</code>、<code>dms.&lt;id&gt;.historyLimit</code></li></ul><hr><h2 id="相关" tabindex="-1">相关 <a class="header-anchor" href="#相关" aria-label="Permalink to &quot;相关&quot;">​</a></h2><ul><li><a href="/channels/pairing.html">配对</a></li><li><a href="/channels/channel-routing.html">渠道路由</a></li><li><a href="/concepts/multi-agent.html">多 Agent 路由</a></li><li><a href="/channels/troubleshooting.html">故障排除</a></li></ul><hr><p><strong>翻译完成时间</strong>: 2026-03-15 01:10<br><strong>来源</strong>: <a href="https://docs.openclaw.ai/channels/whatsapp" target="_blank" rel="noreferrer">https://docs.openclaw.ai/channels/whatsapp</a><br><strong>状态</strong>: ✅ 已完成</p>',138)])])}]]);export{l as __pageData,n as default};
